1	/**
2	 * PLN-01 — auto-dimension chain helpers.
3	 *
4	 * `generateAutoDimensionChain(view, axis)` finds every wall on the
5	 * active level whose run is roughly perpendicular to `axis`, projects
6	 * each endpoint onto that axis, sorts the resulting positions, and
7	 * emits a chain of `createDimension` commands between consecutive
8	 * unique positions.
9	 *
10	 * The dimension chain is offset to one edge of the model bounding box
11	 * (south for axis='x', west for axis='y') so it does not overlap the
12	 * geometry. All produced commands carry `autoGenerated: true` so a
13	 * follow-up `clearAutoGeneratedAnnotations` can wipe them on re-run.
14	 */
15	import type { Element, XY } from '@bim-ai/core';
16	
17	export type AutoDimensionAxis = 'x' | 'y';
18	
19	export type AutoDimensionViewContext = {
20	  /** plan_view id (used so callers can scope clear-and-regenerate). */
21	  planViewId: string;
22	  /** Active level on the plan view — restricts the wall sweep. */
23	  levelId: string;
24	  /** Optional crop bounds; when provided, walls fully outside the crop
25	   * are excluded. */
26	  cropMinMm?: XY | null;
27	  cropMaxMm?: XY | null;
28	};
29	
30	export type CreateDimensionCmd = {
31	  type: 'createDimension';
32	  levelId: string;
33	  aMm: XY;
34	  bMm: XY;
35	  offsetMm: XY;
36	  autoGenerated: true;
37	  name: string;
38	};
39	
40	const PERPENDICULAR_TOLERANCE_DEG = 15;
41	const DUPLICATE_TOLERANCE_MM = 1;
42	const CHAIN_OFFSET_MM = 800;
43	
44	/** Returns walls whose run direction is within ±tolerance of perpendicular
45	 * to the supplied axis. For axis='x' (chain along x), perpendicular walls
46	 * are those running primarily in y. */
47	function isWallPerpendicularToAxis(
48	  wall: Extract<Element, { kind: 'wall' }>,
49	  axis: AutoDimensionAxis,
50	): boolean {
51	  const dx = wall.end.xMm - wall.start.xMm;
52	  const dy = wall.end.yMm - wall.start.yMm;
53	  if (Math.abs(dx) < 1 && Math.abs(dy) < 1) return false;
54	  const angleDeg = (Math.atan2(dy, dx) * 180) / Math.PI;
55	  // For axis='x' we want a wall perpendicular to x = parallel to y =
56	  // angle near ±90.  For axis='y', angle near 0 / 180.
57	  const target = axis === 'x' ? 90 : 0;
58	  const norm = Math.abs(((((angleDeg - target) % 180) + 180) % 180) - 0);
59	  const wrapped = norm > 90 ? 180 - norm : norm;
60	  return wrapped <= PERPENDICULAR_TOLERANCE_DEG;
61	}
62	
63	function dedupeSorted(values: number[], tolMm = DUPLICATE_TOLERANCE_MM): number[] {
64	  const sorted = [...values].sort((a, b) => a - b);
65	  const out: number[] = [];
66	  for (const v of sorted) {
67	    if (out.length === 0 || Math.abs(v - out[out.length - 1]!) > tolMm) {
68	      out.push(v);
69	    }
70	  }
71	  return out;
72	}
73	
74	function modelBoundsMm(
75	  walls: Array<Extract<Element, { kind: 'wall' }>>,
76	): { minXmm: number; maxXmm: number; minYmm: number; maxYmm: number } | null {
77	  if (walls.length === 0) return null;
78	  let minX = Infinity,
79	    maxX = -Infinity,
80	    minY = Infinity,
81	    maxY = -Infinity;
82	  for (const w of walls) {
83	    minX = Math.min(minX, w.start.xMm, w.end.xMm);
84	    maxX = Math.max(maxX, w.start.xMm, w.end.xMm);
85	    minY = Math.min(minY, w.start.yMm, w.end.yMm);
86	    maxY = Math.max(maxY, w.start.yMm, w.end.yMm);
87	  }
88	  return { minXmm: minX, maxXmm: maxX, minYmm: minY, maxYmm: maxY };
89	}
90	
91	function pointInsideCrop(ctx: AutoDimensionViewContext, xMm: number, yMm: number): boolean {
92	  if (!ctx.cropMinMm || !ctx.cropMaxMm) return true;
93	  return (
94	    xMm >= ctx.cropMinMm.xMm &&
95	    xMm <= ctx.cropMaxMm.xMm &&
96	    yMm >= ctx.cropMinMm.yMm &&
97	    yMm <= ctx.cropMaxMm.yMm
98	  );
99	}
100	
101	export function generateAutoDimensionChain(
102	  elementsById: Record<string, Element>,
103	  ctx: AutoDimensionViewContext,
104	  axis: AutoDimensionAxis,
105	): CreateDimensionCmd[] {
106	  const walls: Array<Extract<Element, { kind: 'wall' }>> = [];
107	  for (const el of Object.values(elementsById)) {
108	    if (el.kind !== 'wall') continue;
109	    if (el.levelId !== ctx.levelId) continue;
110	    if (!isWallPerpendicularToAxis(el, axis)) continue;
111	    // Crop filter: include the wall when at least one endpoint sits
112	    // inside the crop frame. (Walls fully outside contribute nothing.)
113	    const inA = pointInsideCrop(ctx, el.start.xMm, el.start.yMm);
114	    const inB = pointInsideCrop(ctx, el.end.xMm, el.end.yMm);
115	    if (!inA && !inB) continue;
116	    walls.push(el);
117	  }
118	  if (walls.length === 0) return [];
119	  const positions: number[] = [];
120	  for (const w of walls) {
121	    if (axis === 'x') {
122	      positions.push(w.start.xMm, w.end.xMm);
123	    } else {
124	      positions.push(w.start.yMm, w.end.yMm);
125	    }
126	  }
127	  const unique = dedupeSorted(positions);
128	  if (unique.length < 2) return [];
129	
130	  const bounds = modelBoundsMm(walls);
131	  if (!bounds) return [];
132	
133	  // Chain offset — south for x-axis chains, west for y-axis chains.
134	  const offY = axis === 'x' ? bounds.minYmm - CHAIN_OFFSET_MM : 0;
135	  const offX = axis === 'y' ? bounds.minXmm - CHAIN_OFFSET_MM : 0;
136	  // The dimension's `offsetMm` is the perpendicular shift from the
137	  // a-b segment to the dim line. createDimension's existing convention
138	  // (PlanCanvas) uses {xMm: -dy/m * 450, yMm: dx/m * 450}; for an
139	  // axis-aligned chain we can supply that directly.
140	  const offsetMm: XY =
141	    axis === 'x' ? { xMm: 0, yMm: -CHAIN_OFFSET_MM } : { xMm: -CHAIN_OFFSET_MM, yMm: 0 };
142	
143	  const cmds: CreateDimensionCmd[] = [];
144	  for (let i = 0; i < unique.length - 1; i++) {
145	    const a = unique[i]!;
146	    const b = unique[i + 1]!;
147	    if (axis === 'x') {
148	      cmds.push({
149	        type: 'createDimension',
150	        levelId: ctx.levelId,
151	        aMm: { xMm: a, yMm: bounds.minYmm },
152	        bMm: { xMm: b, yMm: bounds.minYmm },
153	        offsetMm,
154	        autoGenerated: true,
155	        name: `Auto dim X ${i + 1}`,
156	      });
157	    } else {
158	      cmds.push({
159	        type: 'createDimension',
160	        levelId: ctx.levelId,
161	        aMm: { xMm: bounds.minXmm, yMm: a },
162	        bMm: { xMm: bounds.minXmm, yMm: b },
163	        offsetMm,
164	        autoGenerated: true,
165	        name: `Auto dim Y ${i + 1}`,
166	      });
167	    }
168	  }
169	  // Reference offset shifts so the dim line sits outboard of the model.
170	  void offX;
171	  void offY;
172	  return cmds;
173	}
