1	/* eslint-disable bim-ai/no-hex-in-chrome -- pre-v3 hex literals; remove when this file is migrated in B4 Phase 2 */
2	import { useRef, useState } from 'react';
3	import type { Element, XY } from '@bim-ai/core';
4	import type { JSX } from 'react';
5	
6	import { generateAutoDimensionChain } from './autoDimension';
7	import { clearAutoAnnotationsCommand, generateAutoTags } from './autoTags';
8	
9	/**
10	 * PLN-01 / ANN-01 — Annotate ribbon for the active plan view.
11	 *
12	 * Surfaces the auto-dimension / auto-tag generators (PLN-01) and the
13	 * detail-component creators (ANN-01) as a small inline toolbar. Each
14	 * button packages a sequence of semantic commands and dispatches them
15	 * via `onSemanticCommand`. Auto buttons are idempotent — they emit a
16	 * `clearAutoGeneratedAnnotations` command first, so re-running clears
17	 * the previous output before regenerating.
18	 */
19	export type AnnotateRibbonProps = {
20	  planViewId: string;
21	  levelId: string;
22	  elementsById: Record<string, Element>;
23	  cropMinMm?: XY | null;
24	  cropMaxMm?: XY | null;
25	  onSemanticCommand: (cmd: Record<string, unknown>) => void;
26	};
27	
28	function viewCenter(
29	  elementsById: Record<string, Element>,
30	  cropMinMm: XY | null | undefined,
31	  cropMaxMm: XY | null | undefined,
32	): XY {
33	  if (cropMinMm && cropMaxMm) {
34	    return {
35	      xMm: (cropMinMm.xMm + cropMaxMm.xMm) / 2,
36	      yMm: (cropMinMm.yMm + cropMaxMm.yMm) / 2,
37	    };
38	  }
39	  // Otherwise drop near origin — model bounds are computed elsewhere.
40	  void elementsById;
41	  return { xMm: 0, yMm: 0 };
42	}
43	
44	export function AnnotateRibbon({
45	  planViewId,
46	  levelId,
47	  elementsById,
48	  cropMinMm,
49	  cropMaxMm,
50	  onSemanticCommand,
51	}: AnnotateRibbonProps): JSX.Element {
52	  const ctx = { planViewId, levelId, cropMinMm, cropMaxMm } as const;
53	  const [textNoteInput, setTextNoteInput] = useState(false);
54	  const [textNoteDraft, setTextNoteDraft] = useState('');
55	  const textNoteRef = useRef<HTMLInputElement>(null);
56	
57	  const handleAutoDim = (axis: 'x' | 'y') => {
58	    onSemanticCommand(clearAutoAnnotationsCommand(planViewId, 'dimensions'));
59	    const cmds = generateAutoDimensionChain(elementsById, ctx, axis);
60	    for (const c of cmds) onSemanticCommand(c);
61	  };
62	
63	  const handleAutoTag = (kind: 'room' | 'door' | 'window') => {
64	    onSemanticCommand(clearAutoAnnotationsCommand(planViewId, 'tags'));
65	    const cmds = generateAutoTags(elementsById, ctx, kind);
66	    for (const c of cmds) onSemanticCommand(c);
67	  };
68	
69	  const placeDetailLine = () => {
70	    const c = viewCenter(elementsById, cropMinMm, cropMaxMm);
71	    onSemanticCommand({
72	      type: 'createDetailLine',
73	      hostViewId: planViewId,
74	      pointsMm: [
75	        { xMm: c.xMm - 500, yMm: c.yMm },
76	        { xMm: c.xMm + 500, yMm: c.yMm },
77	      ],
78	      strokeMm: 1.5,
79	      style: 'solid',
80	    });
81	  };
82	
83	  const placeDetailRegion = () => {
84	    const c = viewCenter(elementsById, cropMinMm, cropMaxMm);
85	    onSemanticCommand({
86	      type: 'createDetailRegion',
87	      hostViewId: planViewId,
88	      boundaryMm: [
89	        { xMm: c.xMm - 400, yMm: c.yMm - 400 },
90	        { xMm: c.xMm + 400, yMm: c.yMm - 400 },
91	        { xMm: c.xMm + 400, yMm: c.yMm + 400 },
92	        { xMm: c.xMm - 400, yMm: c.yMm + 400 },
93	      ],
94	      fillPattern: 'hatch_45',
95	      fillColour: '#cccccc',
96	    });
97	  };
98	
99	  const placeAngularDimension = () => {
100	    const c = viewCenter(elementsById, cropMinMm, cropMaxMm);
101	    onSemanticCommand({
102	      type: 'createAngularDimension',
103	      hostViewId: planViewId,
104	      vertexMm: { xMm: c.xMm, yMm: c.yMm },
105	      rayAMm: { xMm: c.xMm + 800, yMm: c.yMm },
106	      rayBMm: { xMm: c.xMm + 565, yMm: c.yMm + 565 },
107	      arcRadiusMm: 400,
108	    });
109	  };
110	
111	  const placeMaskingRegion = () => {
112	    // KRN-10 — drop a square masking region at the view centre. Sketch-based
113	    // boundary authoring is propagated by Agent 4; until then the click-polygon
114	    // fallback is the load-bearing path.
115	    const c = viewCenter(elementsById, cropMinMm, cropMaxMm);
116	    onSemanticCommand({
117	      type: 'createMaskingRegion',
118	      hostViewId: planViewId,
119	      boundaryMm: [
120	        { xMm: c.xMm - 400, yMm: c.yMm - 400 },
121	        { xMm: c.xMm + 400, yMm: c.yMm - 400 },
122	        { xMm: c.xMm + 400, yMm: c.yMm + 400 },
123	        { xMm: c.xMm - 400, yMm: c.yMm + 400 },
124	      ],
125	      fillColor: '#ffffff',
126	    });
127	  };
128	
129	  const placeSpotElevation = () => {
130	    const c = viewCenter(elementsById, cropMinMm, cropMaxMm);
131	    onSemanticCommand({
132	      type: 'createSpotElevation',
133	      hostViewId: planViewId,
134	      positionMm: { xMm: c.xMm, yMm: c.yMm },
135	      elevationMm: 0,
136	    });
137	  };
138	
139	  const placeRadialDimension = () => {
140	    const c = viewCenter(elementsById, cropMinMm, cropMaxMm);
141	    onSemanticCommand({
142	      type: 'createRadialDimension',
143	      hostViewId: planViewId,
144	      centerMm: { xMm: c.xMm, yMm: c.yMm },
145	      arcPointMm: { xMm: c.xMm + 500, yMm: c.yMm },
146	    });
147	  };
148	
149	  const placeDiameterDimension = () => {
150	    const c = viewCenter(elementsById, cropMinMm, cropMaxMm);
151	    onSemanticCommand({
152	      type: 'createDiameterDimension',
153	      hostViewId: planViewId,
154	      centerMm: { xMm: c.xMm, yMm: c.yMm },
155	      arcPointMm: { xMm: c.xMm + 500, yMm: c.yMm },
156	    });
157	  };
158	
159	  const placeArcLengthDimension = () => {
160	    const c = viewCenter(elementsById, cropMinMm, cropMaxMm);
161	    onSemanticCommand({
162	      type: 'createArcLengthDimension',
163	      hostViewId: planViewId,
164	      centerMm: { xMm: c.xMm, yMm: c.yMm },
165	      radiusMm: 500,
166	      startAngleDeg: 0,
167	      endAngleDeg: 90,
168	    });
169	  };
170	
171	  const placeMaterialTag = () => {
172	    const c = viewCenter(elementsById, cropMinMm, cropMaxMm);
173	    onSemanticCommand({
174	      type: 'createMaterialTag',
175	      hostViewId: planViewId,
176	      hostElementId: '',
177	      layerIndex: 0,
178	      positionMm: { xMm: c.xMm, yMm: c.yMm },
179	    });
180	  };
181	
182	  const placeMultiCategoryTag = () => {
183	    const c = viewCenter(elementsById, cropMinMm, cropMaxMm);
184	    onSemanticCommand({
185	      type: 'createMultiCategoryTag',
186	      hostViewId: planViewId,
187	      hostElementId: '',
188	      positionMm: { xMm: c.xMm, yMm: c.yMm },
189	    });
190	  };
191	
192	  const placeTreadNumber = () => {
193	    const c = viewCenter(elementsById, cropMinMm, cropMaxMm);
194	    void c;
195	    onSemanticCommand({
196	      type: 'createTreadNumber',
197	      hostViewId: planViewId,
198	      stairElementId: '',
199	    });
200	  };
201	
202	  const placeKeynote = () => {
203	    const c = viewCenter(elementsById, cropMinMm, cropMaxMm);
204	    onSemanticCommand({
205	      type: 'createKeynote',
206	      hostViewId: planViewId,
207	      positionMm: { xMm: c.xMm, yMm: c.yMm },
208	      keynoteKey: 'A1',
209	      keynoteText: '',
210	    });
211	  };
212	
213	  const placeSpanDirection = () => {
214	    const c = viewCenter(elementsById, cropMinMm, cropMaxMm);
215	    onSemanticCommand({
216	      type: 'createSpanDirection',
217	      hostViewId: planViewId,
218	      positionMm: { xMm: c.xMm, yMm: c.yMm },
219	      directionDeg: 0,
220	    });
221	  };
222	
223	  const placePipeLegend = () => {
224	    const c = viewCenter(elementsById, cropMinMm, cropMaxMm);
225	    onSemanticCommand({
226	      type: 'createPipeLegend',
227	      hostViewId: planViewId,
228	      positionMm: { xMm: c.xMm, yMm: c.yMm },
229	      title: 'Pipe Legend',
230	      entries: [
231	        { systemType: 'domestic_cold_water', label: 'Cold Water', colour: '#0066cc' },
232	        { systemType: 'domestic_hot_water', label: 'Hot Water', colour: '#cc3300' },
233	        { systemType: 'sanitary', label: 'Sanitary', colour: '#996633' },
234	        { systemType: 'fire_protection', label: 'Fire Protection', colour: '#cc0000' },
235	      ],
236	    });
237	  };
238	
239	  const placeDuctLegend = () => {
240	    const c = viewCenter(elementsById, cropMinMm, cropMaxMm);
241	    onSemanticCommand({
