1640	  const onSemanticCommand = useCallback(
1641	    async (cmd: Record<string, unknown>): Promise<void> => {
1642	      const mid = useBimStore.getState().modelId;
1643	      const uid = useBimStore.getState().userId;
1644	      if (!mid) return;
1645	      const clientOpId = `web-${Date.now().toString(36)}-${Math.random().toString(36).slice(2, 10)}`;
1646	      rememberLocalClientOp(clientOpId);
1647	      try {
1648	        const r = await applyCommand(mid, cmd, { userId: uid, clientOpId });
1649	        if (r.revision !== undefined) {
1650	          if (r.delta) {
1651	            useBimStore.getState().applyDelta(r.delta as ModelDelta);
1652	          } else {
1653	            hydrateFromSnapshot({
1654	              modelId: mid,
1655	              revision: r.revision,
1656	              elements: r.elements ?? {},
1657	              violations: (r.violations ?? []) as Violation[],
1658	            });
1659	          }
1660	          syncLastLevelElevationPropagationFromApplyResponse(
1661	            r as Parameters<typeof syncLastLevelElevationPropagationFromApplyResponse>[0],
1662	          );
1663	          setUndoDepth((d) => d + 1);
1664	          setRedoDepth(0);
1665	        }
1666	        setCollaborationConflictQueue(null);
1667	      } catch (err) {
1668	        if (err instanceof ApiHttpError && err.status === 409) {
1669	          log.error('conflict', '409 conflict detail:', err.detail);
1670	          setCollaborationConflictQueue(buildCollaborationConflictQueueV1(err.detail));
1671	        } else {
1672	          setCollaborationConflictQueue(null);
1673	          setSeedError(err instanceof Error ? err.message : 'Apply failed');
1674	        }
1675	      }
1676	    },
1677	    [hydrateFromSnapshot, setSeedError],
1678	  );
1679	
1680	  const deleteSelectedElements = useCallback((): boolean => {
1681	    const st = useBimStore.getState();
1682	    const idsToDelete = [
1683	      ...new Set(
1684	        [st.selectedId, ...st.selectedIds].filter((id): id is string => typeof id === 'string'),
1685	      ),
1686	    ];
1687	    if (idsToDelete.length === 0) return false;
1688	    void onSemanticCommand(
1689	      idsToDelete.length === 1
1690	        ? { type: 'deleteElement', elementId: idsToDelete[0] }
