    } else if (p.kind === 'annotation_symbol') {
      const labelCanvas = document.createElement('canvas');
      labelCanvas.width = 128;
      labelCanvas.height = 128;
      const lctx = labelCanvas.getContext('2d');
      if (lctx) {
        lctx.fillStyle = p.colour;
        if (p.symbolType === 'north_arrow') {
          lctx.beginPath();
          lctx.moveTo(64, 8);
          lctx.lineTo(80, 100);
          lctx.lineTo(64, 84);
          lctx.lineTo(48, 100);
          lctx.closePath();
          lctx.fill();
          lctx.fillStyle = '#ffffff';
          lctx.beginPath();
          lctx.moveTo(64, 8);
          lctx.lineTo(64, 84);
          lctx.lineTo(48, 100);
          lctx.closePath();
          lctx.fill();
          lctx.fillStyle = p.colour;
          lctx.font = 'bold 28px sans-serif';
          lctx.textAlign = 'center';
          lctx.fillText('N', 64, 120);
        } else if (p.symbolType === 'stair_up' || p.symbolType === 'stair_down') {
          lctx.font = '80px sans-serif';
          lctx.textAlign = 'center';
          lctx.textBaseline = 'middle';
          lctx.fillText(p.symbolType === 'stair_up' ? '↑' : '↓', 64, 64);
        } else {
          lctx.beginPath();
          lctx.moveTo(4, 64);
          lctx.lineTo(124, 64);
          lctx.strokeStyle = p.colour;
          lctx.lineWidth = 4;
          lctx.stroke();
          lctx.beginPath();
          lctx.moveTo(64, 4);
          lctx.lineTo(64, 124);
          lctx.stroke();
        }
      }
      const symTex = new THREE.CanvasTexture(labelCanvas);
      symTex.minFilter = THREE.LinearFilter;
      const symMat = new THREE.SpriteMaterial({ map: symTex, transparent: true });
      const symSprite = new THREE.Sprite(symMat);
      const symSizeM = 0.4 * (p.scale ?? 1);
      symSprite.scale.set(symSizeM, symSizeM, 1);
      symSprite.position.set(
        p.positionMm.xMm / 1000,
        SLICE_Y + 0.011,
        p.positionMm.yMm / 1000,
      );
      symSprite.userData.detailComponent = true;
      symSprite.userData.bimPickId = p.id;
      grp.add(symSprite);
    } else if (p.kind === 'spot_elevation') {
      const elevM = p.elevationMm / 1000;
      const label = `${p.prefix}${elevM >= 0 ? '+' : ''}${elevM.toFixed(3)}${p.suffix}`;
      const seLabelCanvas = document.createElement('canvas');
      seLabelCanvas.width = 256;
      seLabelCanvas.height = 48;
      const sectx = seLabelCanvas.getContext('2d');
      if (sectx) {
        sectx.fillStyle = p.colour;
        sectx.font = '28px sans-serif';
        sectx.textBaseline = 'middle';
        sectx.fillText(label, 4, 24);
      }
      const seTex = new THREE.CanvasTexture(seLabelCanvas);
      seTex.minFilter = THREE.LinearFilter;
      const seMat = new THREE.SpriteMaterial({ map: seTex, transparent: true });
      const seSprite = new THREE.Sprite(seMat);
      seSprite.scale.set(0.5, 0.1, 1);
      seSprite.position.set(
        p.positionMm.xMm / 1000 + 0.12,
        SLICE_Y + 0.011,
        p.positionMm.yMm / 1000,
      );
      seSprite.userData.detailComponent = true;
      seSprite.userData.bimPickId = p.id;
      grp.add(seSprite);
      // Draw the downward triangle tick
      const seTickPts = [
        new THREE.Vector3(p.positionMm.xMm / 1000, SLICE_Y + 0.005, p.positionMm.yMm / 1000),
        new THREE.Vector3(
          p.positionMm.xMm / 1000 - 0.05,
          SLICE_Y + 0.005,
          p.positionMm.yMm / 1000 - 0.09,
        ),
        new THREE.Vector3(
          p.positionMm.xMm / 1000 + 0.05,
          SLICE_Y + 0.005,
          p.positionMm.yMm / 1000 - 0.09,
        ),
        new THREE.Vector3(p.positionMm.xMm / 1000, SLICE_Y + 0.005, p.positionMm.yMm / 1000),
      ];
      const seTickGeom = new THREE.BufferGeometry().setFromPoints(seTickPts);
      const seTick = new THREE.Line(
        seTickGeom,
        new THREE.LineBasicMaterial({ color: p.colour }),
      );
      seTick.userData.detailComponent = true;
      grp.add(seTick);
    } else if (p.kind === 'radial_dimension') {
      const rdx1 = p.centerMm.xMm / 1000;
      const rdz1 = p.centerMm.yMm / 1000;
      const rdx2 = p.arcPointMm.xMm / 1000;
      const rdz2 = p.arcPointMm.yMm / 1000;
      const rdRadius = Math.sqrt((rdx2 - rdx1) ** 2 + (rdz2 - rdz1) ** 2);
      const rdPts = [
        new THREE.Vector3(rdx1, SLICE_Y + 0.005, rdz1),
        new THREE.Vector3(rdx2, SLICE_Y + 0.005, rdz2),
      ];
      const rdGeom = new THREE.BufferGeometry().setFromPoints(rdPts);
      const rdLine = new THREE.Line(
        rdGeom,
        new THREE.LineBasicMaterial({ color: p.colour }),
      );
      rdLine.userData.detailComponent = true;
      rdLine.userData.bimPickId = p.id;
      grp.add(rdLine);
      const rdLabelCanvas = document.createElement('canvas');
      rdLabelCanvas.width = 180;
      rdLabelCanvas.height = 40;
      const rdCtx = rdLabelCanvas.getContext('2d');
      if (rdCtx) {
        rdCtx.fillStyle = p.colour;
        rdCtx.font = '24px sans-serif';
        rdCtx.textBaseline = 'middle';
        rdCtx.fillText(`R ${Math.round(rdRadius * 1000)}`, 4, 20);
      }
      const rdTex = new THREE.CanvasTexture(rdLabelCanvas);
      rdTex.minFilter = THREE.LinearFilter;
      const rdSpr = new THREE.Sprite(
        new THREE.SpriteMaterial({ map: rdTex, transparent: true }),
      );
      rdSpr.scale.set(0.35, 0.08, 1);
      rdSpr.position.set((rdx1 + rdx2) / 2, SLICE_Y + 0.011, (rdz1 + rdz2) / 2 - 0.08);
      rdSpr.userData.detailComponent = true;
      grp.add(rdSpr);
    } else if (p.kind === 'diameter_dimension') {
      const ddx1 = p.centerMm.xMm / 1000;
      const ddz1 = p.centerMm.yMm / 1000;
      const ddx2 = p.arcPointMm.xMm / 1000;
      const ddz2 = p.arcPointMm.yMm / 1000;
      const ddRadius = Math.sqrt((ddx2 - ddx1) ** 2 + (ddz2 - ddz1) ** 2);
      const ddDirX = ddRadius > 0 ? (ddx2 - ddx1) / ddRadius : 1;
      const ddDirZ = ddRadius > 0 ? (ddz2 - ddz1) / ddRadius : 0;
      const ddPts = [
        new THREE.Vector3(
          ddx1 - ddDirX * ddRadius,
          SLICE_Y + 0.005,
          ddz1 - ddDirZ * ddRadius,
        ),
        new THREE.Vector3(
          ddx1 + ddDirX * ddRadius,
          SLICE_Y + 0.005,
          ddz1 + ddDirZ * ddRadius,
        ),
      ];
      const ddGeom = new THREE.BufferGeometry().setFromPoints(ddPts);
      const ddLine = new THREE.Line(
        ddGeom,
        new THREE.LineBasicMaterial({ color: p.colour }),
      );
      ddLine.userData.detailComponent = true;
      ddLine.userData.bimPickId = p.id;
      grp.add(ddLine);
      const ddLabelCanvas = document.createElement('canvas');
      ddLabelCanvas.width = 200;
      ddLabelCanvas.height = 40;
      const ddCtx = ddLabelCanvas.getContext('2d');
      if (ddCtx) {
        ddCtx.fillStyle = p.colour;
        ddCtx.font = '24px sans-serif';
        ddCtx.textBaseline = 'middle';
        ddCtx.fillText(`⌀ ${Math.round(ddRadius * 2000)}`, 4, 20);
      }
      const ddTex = new THREE.CanvasTexture(ddLabelCanvas);
      ddTex.minFilter = THREE.LinearFilter;
      const ddSpr = new THREE.Sprite(
