      ssSpr.scale.set(0.4, 0.09, 1);
      ssSpr.position.set(
        p.positionMm.xMm / 1000,
        SLICE_Y + 0.011,
        p.positionMm.yMm / 1000,
      );
      ssSpr.userData.detailComponent = true;
      ssSpr.userData.bimPickId = p.id;
      grp.add(ssSpr);
    } else if (p.kind === 'material_tag') {
      const mtCanvas = document.createElement('canvas');
      mtCanvas.width = 256;
      mtCanvas.height = 40;
      const mtCtx = mtCanvas.getContext('2d');
      const mtLabel = p.textOverride ?? `[Mtl:${p.layerIndex}]`;
      if (mtCtx) {
        mtCtx.fillStyle = p.colour;
        mtCtx.font = '24px sans-serif';
        mtCtx.textBaseline = 'middle';
        mtCtx.fillText(mtLabel, 4, 20);
      }
      const mtTex = new THREE.CanvasTexture(mtCanvas);
      mtTex.minFilter = THREE.LinearFilter;
      const mtSpr = new THREE.Sprite(
        new THREE.SpriteMaterial({ map: mtTex, transparent: true }),
      );
      mtSpr.scale.set(0.5, 0.08, 1);
      mtSpr.position.set(
        p.positionMm.xMm / 1000,
        SLICE_Y + 0.011,
        p.positionMm.yMm / 1000,
      );
      mtSpr.userData.detailComponent = true;
      mtSpr.userData.bimPickId = p.id;
      grp.add(mtSpr);
    } else if (p.kind === 'insulation_annotation') {
      const insX1 = p.startMm.xMm / 1000;
      const insZ1 = p.startMm.yMm / 1000;
      const insX2 = p.endMm.xMm / 1000;
      const insZ2 = p.endMm.yMm / 1000;
      const insLen = Math.sqrt((insX2 - insX1) ** 2 + (insZ2 - insZ1) ** 2);
      if (insLen > 0) {
        const insDirX = (insX2 - insX1) / insLen;
        const insDirZ = (insZ2 - insZ1) / insLen;
        const insPerpX = -insDirZ;
        const insPerpZ = insDirX;
        const insW = (p.widthMm ?? 200) / 2000;
        const numBumps = Math.max(3, Math.floor(insLen / 0.1));
        const insPts: THREE.Vector3[] = [];
        for (let bi = 0; bi <= numBumps * 2; bi++) {
          const t2 = bi / (numBumps * 2);
          const side = bi % 2 === 0 ? 0 : insW;
          insPts.push(
            new THREE.Vector3(
              insX1 + insDirX * insLen * t2 + insPerpX * side,
              SLICE_Y + 0.005,
              insZ1 + insDirZ * insLen * t2 + insPerpZ * side,
            ),
          );
        }
        const insGeom = new THREE.BufferGeometry().setFromPoints(insPts);
        const insLine = new THREE.Line(
          insGeom,
          new THREE.LineBasicMaterial({ color: p.colour }),
        );
        insLine.userData.detailComponent = true;
        insLine.userData.bimPickId = p.id;
        grp.add(insLine);
      }
    } else if (p.kind === 'revision_cloud') {
      if (p.boundaryMm.length >= 3) {
        const rcPts = p.boundaryMm.map(
          (pt) => new THREE.Vector3(pt.xMm / 1000, SLICE_Y + 0.005, pt.yMm / 1000),
        );
        rcPts.push(rcPts[0]!.clone());
        const rcGeom = new THREE.BufferGeometry().setFromPoints(rcPts);
        const rcLine = new THREE.Line(
          rcGeom,
          new THREE.LineDashedMaterial({
            color: p.colour,
            dashSize: 0.05,
            gapSize: 0.03,
            linewidth: p.strokeMm,
          }),
        );
        rcLine.computeLineDistances();
        rcLine.userData.detailComponent = true;
        rcLine.userData.bimPickId = p.id;
        grp.add(rcLine);
      }
    } else if (p.kind === 'angular_dimension') {
      const avx = p.vertexMm.xMm / 1000;
      const avz = p.vertexMm.yMm / 1000;
      const aax = p.rayAMm.xMm / 1000;
      const aaz = p.rayAMm.yMm / 1000;
      const abx = p.rayBMm.xMm / 1000;
      const abz = p.rayBMm.yMm / 1000;
      const angleA = Math.atan2(aaz - avz, aax - avx);
      const angleB = Math.atan2(abz - avz, abx - avx);
      const arcR = p.arcRadiusMm / 1000;
      const rayAPts = [
        new THREE.Vector3(avx, SLICE_Y + 0.005, avz),
        new THREE.Vector3(avx + Math.cos(angleA) * arcR, SLICE_Y + 0.005, avz + Math.sin(angleA) * arcR),
      ];
      const rayBPts = [
        new THREE.Vector3(avx, SLICE_Y + 0.005, avz),
        new THREE.Vector3(avx + Math.cos(angleB) * arcR, SLICE_Y + 0.005, avz + Math.sin(angleB) * arcR),
      ];
      const adMat = new THREE.LineBasicMaterial({ color: p.colour });
      const adGeomA = new THREE.BufferGeometry().setFromPoints(rayAPts);
      const adGeomB = new THREE.BufferGeometry().setFromPoints(rayBPts);
      const rayALine = new THREE.Line(adGeomA, adMat);
      const rayBLine = new THREE.Line(adGeomB, adMat);
      rayALine.userData.detailComponent = true;
      rayBLine.userData.detailComponent = true;
      rayALine.userData.bimPickId = p.id;
      grp.add(rayALine);
      grp.add(rayBLine);
      const adSegs = 20;
      const adArcPts: THREE.Vector3[] = [];
      let startA = angleA;
      let endA = angleB;
      if (endA < startA) endA += Math.PI * 2;
      for (let si = 0; si <= adSegs; si++) {
        const a = startA + (endA - startA) * (si / adSegs);
        adArcPts.push(
          new THREE.Vector3(avx + Math.cos(a) * arcR, SLICE_Y + 0.005, avz + Math.sin(a) * arcR),
        );
      }
      const adArcGeom = new THREE.BufferGeometry().setFromPoints(adArcPts);
      const adArcLine = new THREE.Line(adArcGeom, adMat.clone());
      adArcLine.userData.detailComponent = true;
      grp.add(adArcLine);
      const adAngleDeg = Math.abs(((endA - startA) * 180) / Math.PI);
      const adLabelCanvas = document.createElement('canvas');
      adLabelCanvas.width = 160;
      adLabelCanvas.height = 40;
      const adCtx = adLabelCanvas.getContext('2d');
      if (adCtx) {
        adCtx.fillStyle = p.colour;
        adCtx.font = '24px sans-serif';
        adCtx.textBaseline = 'middle';
        adCtx.fillText(`${adAngleDeg.toFixed(1)}°`, 4, 20);
      }
      const adTex = new THREE.CanvasTexture(adLabelCanvas);
      adTex.minFilter = THREE.LinearFilter;
      const adSpr = new THREE.Sprite(
        new THREE.SpriteMaterial({ map: adTex, transparent: true }),
      );
      const adMidA = (startA + endA) / 2;
      adSpr.scale.set(0.3, 0.08, 1);
      adSpr.position.set(
        avx + Math.cos(adMidA) * (arcR + 0.1),
        SLICE_Y + 0.011,
        avz + Math.sin(adMidA) * (arcR + 0.1),
      );
      adSpr.userData.detailComponent = true;
      grp.add(adSpr);
    }
  }
}

