        state: { ...state, draft: state.draft.slice(0, -1) },
        effect: { stillActive: true },
      };
    }
    if (event.kind === 'confirm' && state.draft.trim().length > 0) {
      return {
        state: initialTextAnnotationState(),
        effect: { commitText: { positionMm: state.positionMm, content: state.draft }, stillActive: true },
      };
    }
  }
  return { state, effect: { stillActive: true } };
}

/* ────────────────────────────────────────────────────────────────────── */
/* A2 Leader Text — anchor → (elbow) → text placement → type             */
/* ────────────────────────────────────────────────────────────────────── */

export type LeaderTextState =
  | { phase: 'idle' }
  | { phase: 'anchor'; anchorMm: { xMm: number; yMm: number } }
  | { phase: 'text-pos'; anchorMm: { xMm: number; yMm: number }; elbowMm: { xMm: number; yMm: number } }
  | { phase: 'typing'; anchorMm: { xMm: number; yMm: number }; elbowMm: { xMm: number; yMm: number }; textMm: { xMm: number; yMm: number }; draft: string };

export type LeaderTextEvent =
  | { kind: 'activate' }
  | { kind: 'deactivate' }
  | { kind: 'click'; pointMm: { xMm: number; yMm: number } }
  | { kind: 'type'; char: string }
  | { kind: 'backspace' }
  | { kind: 'confirm' }
  | { kind: 'cancel' };

export interface LeaderTextEffect {
  commitLeader?: {
    anchorMm: { xMm: number; yMm: number };
    elbowMm: { xMm: number; yMm: number };
    textMm: { xMm: number; yMm: number };
    content: string;
  };
  stillActive: boolean;
}

export function initialLeaderTextState(): LeaderTextState {
  return { phase: 'idle' };
}

export function reduceLeaderText(
  state: LeaderTextState,
  event: LeaderTextEvent,
): { state: LeaderTextState; effect: LeaderTextEffect } {
  if (event.kind === 'deactivate') {
    return { state: initialLeaderTextState(), effect: { stillActive: false } };
  }
  if (event.kind === 'activate' || event.kind === 'cancel') {
    return { state: initialLeaderTextState(), effect: { stillActive: event.kind === 'activate' } };
  }
  if (event.kind === 'click') {
    if (state.phase === 'idle') {
      return { state: { phase: 'anchor', anchorMm: event.pointMm }, effect: { stillActive: true } };
    }
    if (state.phase === 'anchor') {
      return {
        state: { phase: 'text-pos', anchorMm: state.anchorMm, elbowMm: event.pointMm },
        effect: { stillActive: true },
      };
    }
    if (state.phase === 'text-pos') {
      return {
        state: { phase: 'typing', anchorMm: state.anchorMm, elbowMm: state.elbowMm, textMm: event.pointMm, draft: '' },
        effect: { stillActive: true },
      };
    }
  }
  if (state.phase === 'typing') {
    if (event.kind === 'type') {
      return { state: { ...state, draft: state.draft + event.char }, effect: { stillActive: true } };
    }
    if (event.kind === 'backspace') {
      return { state: { ...state, draft: state.draft.slice(0, -1) }, effect: { stillActive: true } };
    }
    if (event.kind === 'confirm' && state.draft.trim().length > 0) {
      return {
        state: initialLeaderTextState(),
        effect: {
          commitLeader: { anchorMm: state.anchorMm, elbowMm: state.elbowMm, textMm: state.textMm, content: state.draft },
          stillActive: true,
        },
      };
    }
  }
  return { state, effect: { stillActive: true } };
}

/* ────────────────────────────────────────────────────────────────────── */
/* A4 Angular Dimension — line1 vertex → line1 point → line2 point       */
/* ────────────────────────────────────────────────────────────────────── */

export type AngularDimensionState =
  | { phase: 'idle' }
  | { phase: 'first-ray'; vertexMm: { xMm: number; yMm: number }; rayAMm: { xMm: number; yMm: number } }
  | { phase: 'second-ray'; vertexMm: { xMm: number; yMm: number }; rayAMm: { xMm: number; yMm: number } };

export type AngularDimensionEvent =
  | { kind: 'activate' }
  | { kind: 'deactivate' }
  | { kind: 'click'; pointMm: { xMm: number; yMm: number } }
  | { kind: 'cancel' };

export interface AngularDimensionEffect {
  commitAngular?: {
    vertexMm: { xMm: number; yMm: number };
    rayAMm: { xMm: number; yMm: number };
    rayBMm: { xMm: number; yMm: number };
    arcRadiusMm: number;
  };
  stillActive: boolean;
}

export function initialAngularDimensionState(): AngularDimensionState {
  return { phase: 'idle' };
}

export function reduceAngularDimension(
  state: AngularDimensionState,
  event: AngularDimensionEvent,
): { state: AngularDimensionState; effect: AngularDimensionEffect } {
  if (event.kind === 'deactivate') {
    return { state: initialAngularDimensionState(), effect: { stillActive: false } };
  }
  if (event.kind === 'activate' || event.kind === 'cancel') {
    return { state: initialAngularDimensionState(), effect: { stillActive: event.kind === 'activate' } };
  }
  if (event.kind === 'click') {
    if (state.phase === 'idle') {
      return { state: { phase: 'first-ray', vertexMm: event.pointMm, rayAMm: event.pointMm }, effect: { stillActive: true } };
    }
    if (state.phase === 'first-ray') {
      return {
        state: { phase: 'second-ray', vertexMm: state.vertexMm, rayAMm: event.pointMm },
        effect: { stillActive: true },
      };
    }
    if (state.phase === 'second-ray') {
      const dx = event.pointMm.xMm - state.vertexMm.xMm;
      const dy = event.pointMm.yMm - state.vertexMm.yMm;
      const arcRadiusMm = Math.sqrt(dx * dx + dy * dy) * 0.5;
      return {
        state: initialAngularDimensionState(),
        effect: {
          commitAngular: { vertexMm: state.vertexMm, rayAMm: state.rayAMm, rayBMm: event.pointMm, arcRadiusMm },
          stillActive: true,
        },
      };
    }
  }
  return { state, effect: { stillActive: true } };
}

/* ────────────────────────────────────────────────────────────────────── */
/* A5/A6 Radial / Diameter / Arc-Length — two-click: center + arc point  */
/* ────────────────────────────────────────────────────────────────────── */

export type RadialDimensionState =
  | { phase: 'idle' }
  | { phase: 'arc-point'; centerMm: { xMm: number; yMm: number } };

export type RadialDimensionEvent =
  | { kind: 'activate' }
  | { kind: 'deactivate' }
  | { kind: 'click'; pointMm: { xMm: number; yMm: number } }
  | { kind: 'cancel' };

export interface RadialDimensionEffect {
  commitRadial?: { centerMm: { xMm: number; yMm: number }; arcPointMm: { xMm: number; yMm: number } };
  stillActive: boolean;
}

export function initialRadialDimensionState(): RadialDimensionState {
  return { phase: 'idle' };
}

export function reduceRadialDimension(
  state: RadialDimensionState,
  event: RadialDimensionEvent,
): { state: RadialDimensionState; effect: RadialDimensionEffect } {
  if (event.kind === 'deactivate') {
    return { state: initialRadialDimensionState(), effect: { stillActive: false } };
  }
  if (event.kind === 'activate' || event.kind === 'cancel') {
    return { state: initialRadialDimensionState(), effect: { stillActive: event.kind === 'activate' } };
  }
  if (event.kind === 'click') {
    if (state.phase === 'idle') {
      return { state: { phase: 'arc-point', centerMm: event.pointMm }, effect: { stillActive: true } };
    }
    if (state.phase === 'arc-point') {
      return {
        state: initialRadialDimensionState(),
        effect: { commitRadial: { centerMm: state.centerMm, arcPointMm: event.pointMm }, stillActive: true },
      };
    }
  }
  return { state, effect: { stillActive: true } };
}

/* ────────────────────────────────────────────────────────────────────── */
/* A7/A8/A9/A10/A12 Single-click placement annotation tools               */
/* ────────────────────────────────────────────────────────────────────── */

export type SingleClickAnnotationState = { phase: 'idle' };

export type SingleClickAnnotationEvent =
  | { kind: 'activate' }
  | { kind: 'deactivate' }
  | { kind: 'click'; pointMm: { xMm: number; yMm: number } }
  | { kind: 'cancel' };

export interface SingleClickAnnotationEffect {
  commitPoint?: { positionMm: { xMm: number; yMm: number } };
  stillActive: boolean;
}

export function initialSingleClickAnnotationState(): SingleClickAnnotationState {
  return { phase: 'idle' };
}

export function reduceSingleClickAnnotation(
  state: SingleClickAnnotationState,
  event: SingleClickAnnotationEvent,
): { state: SingleClickAnnotationState; effect: SingleClickAnnotationEffect } {
  if (event.kind === 'deactivate') {
    return { state: initialSingleClickAnnotationState(), effect: { stillActive: false } };
  }
  if (event.kind === 'activate' || event.kind === 'cancel') {
    return { state: initialSingleClickAnnotationState(), effect: { stillActive: event.kind === 'activate' } };
  }
  if (event.kind === 'click') {
    return {
      state: initialSingleClickAnnotationState(),
      effect: { commitPoint: { positionMm: event.pointMm }, stillActive: true },
    };
  }
  return { state, effect: { stillActive: true } };
}

/* ────────────────────────────────────────────────────────────────────── */
/* A9 Slope Annotation — two-click: start point + end point               */
/* ────────────────────────────────────────────────────────────────────── */

export type SlopeAnnotationState =
  | { phase: 'idle' }
  | { phase: 'end-point'; startMm: { xMm: number; yMm: number } };

export type SlopeAnnotationEvent =
  | { kind: 'activate' }
  | { kind: 'deactivate' }
  | { kind: 'click'; pointMm: { xMm: number; yMm: number } }
  | { kind: 'cancel' };

export interface SlopeAnnotationEffect {
  commitSlope?: { startMm: { xMm: number; yMm: number }; endMm: { xMm: number; yMm: number } };
  stillActive: boolean;
}

export function initialSlopeAnnotationState(): SlopeAnnotationState {
  return { phase: 'idle' };
}

export function reduceSlopeAnnotation(
  state: SlopeAnnotationState,
  event: SlopeAnnotationEvent,
): { state: SlopeAnnotationState; effect: SlopeAnnotationEffect } {
  if (event.kind === 'deactivate') {
    return { state: initialSlopeAnnotationState(), effect: { stillActive: false } };
  }
  if (event.kind === 'activate' || event.kind === 'cancel') {
    return { state: initialSlopeAnnotationState(), effect: { stillActive: event.kind === 'activate' } };
  }
  if (event.kind === 'click') {
    if (state.phase === 'idle') {
      return { state: { phase: 'end-point', startMm: event.pointMm }, effect: { stillActive: true } };
    }
    if (state.phase === 'end-point') {
      return {
        state: initialSlopeAnnotationState(),
        effect: { commitSlope: { startMm: state.startMm, endMm: event.pointMm }, stillActive: true },
      };
    }
  }
  return { state, effect: { stillActive: true } };
}

