      p.kind === 'spot_coordinate' ||
      p.kind === 'spot_slope' ||
      p.kind === 'material_tag'
    ) {
      // Render as a labelled sprite at the annotation position.
      const labelText =
        p.kind === 'spot_elevation'
          ? `${p.prefix}${(p.elevationMm / 1000).toFixed(3)}${p.suffix}`
          : p.kind === 'spot_coordinate'
            ? `N${(p.northMm / 1000).toFixed(2)} E${(p.eastMm / 1000).toFixed(2)}`
            : p.kind === 'spot_slope'
              ? p.slopeFormat === 'percent'
                ? `${p.slopePct.toFixed(1)}%`
                : p.slopeFormat === 'ratio'
                  ? `1:${(100 / p.slopePct).toFixed(0)}`
                  : `${p.slopePct.toFixed(1)}°`
              : p.kind === 'material_tag'
                ? (p.textOverride ?? 'Material')
                : p.symbolType;
      const ac = document.createElement('canvas');
      ac.width = 256;
      ac.height = 64;
      const ac2 = ac.getContext('2d');
      if (ac2) {
        ac2.fillStyle = p.colour;
        ac2.font = '28px sans-serif';
        ac2.textBaseline = 'middle';
        ac2.fillText(labelText, 4, 32);
      }
      const aTex = new THREE.CanvasTexture(ac);
      aTex.minFilter = THREE.LinearFilter;
      const aMat = new THREE.SpriteMaterial({ map: aTex, transparent: true });
      const aSprite = new THREE.Sprite(aMat);
      const aH = 0.3;
      aSprite.scale.set(aH * (ac.width / ac.height), aH, 1);
      const aPos = 'positionMm' in p ? p.positionMm : { xMm: 0, yMm: 0 };
      aSprite.position.set(aPos.xMm / 1000, SLICE_Y + 0.01, aPos.yMm / 1000);
      aSprite.userData.detailComponent = true;
      aSprite.userData.bimPickId = p.id;
      grp.add(aSprite);
    } else if (p.kind === 'radial_dimension' || p.kind === 'diameter_dimension') {
      // Render as a line from arc point toward centre with a label.
      const lineMat = new THREE.LineBasicMaterial({ color: p.colour });
      const pts = [
        new THREE.Vector3(p.arcPointMm.xMm / 1000, SLICE_Y + 0.01, p.arcPointMm.yMm / 1000),
        new THREE.Vector3(p.centerMm.xMm / 1000, SLICE_Y + 0.01, p.centerMm.yMm / 1000),
      ];
      const geo = new THREE.BufferGeometry().setFromPoints(pts);
      const line = new THREE.Line(geo, lineMat);
      line.userData.detailComponent = true;
      line.userData.bimPickId = p.id;
      grp.add(line);
      const dx = p.arcPointMm.xMm - p.centerMm.xMm;
      const dy = p.arcPointMm.yMm - p.centerMm.yMm;
      const rMm = Math.sqrt(dx * dx + dy * dy);
      const rdLabel = p.kind === 'diameter_dimension' ? `⌀${(rMm * 2).toFixed(0)}` : `R${rMm.toFixed(0)}`;
      const rdCanvas = document.createElement('canvas');
      rdCanvas.width = 192;
      rdCanvas.height = 64;
      const rdCtx = rdCanvas.getContext('2d');
      if (rdCtx) {
        rdCtx.fillStyle = p.colour;
        rdCtx.font = '28px sans-serif';
        rdCtx.textBaseline = 'middle';
        rdCtx.fillText(rdLabel, 4, 32);
      }
      const rdTex = new THREE.CanvasTexture(rdCanvas);
      rdTex.minFilter = THREE.LinearFilter;
      const rdMat = new THREE.SpriteMaterial({ map: rdTex, transparent: true });
      const rdSprite = new THREE.Sprite(rdMat);
      const rdH = 0.25;
      rdSprite.scale.set(rdH * (rdCanvas.width / rdCanvas.height), rdH, 1);
      rdSprite.position.set(
        ((p.arcPointMm.xMm + p.centerMm.xMm) / 2) / 1000,
        SLICE_Y + 0.01,
        ((p.arcPointMm.yMm + p.centerMm.yMm) / 2) / 1000,
      );
      rdSprite.userData.detailComponent = true;
      rdSprite.userData.bimPickId = p.id;
      grp.add(rdSprite);
    } else if (p.kind === 'arc_length_dimension') {
      // Render as a label at the arc midpoint.
      const arcMidAngleDeg = (p.startAngleDeg + p.endAngleDeg) / 2;
      const arcMidRad = (arcMidAngleDeg * Math.PI) / 180;
      const arcMidX = p.centerMm.xMm + p.radiusMm * Math.cos(arcMidRad);
      const arcMidY = p.centerMm.yMm + p.radiusMm * Math.sin(arcMidRad);
      const arcLenMm =
        ((Math.abs(p.endAngleDeg - p.startAngleDeg) * Math.PI) / 180) * p.radiusMm;
      const arcCanvas = document.createElement('canvas');
      arcCanvas.width = 192;
      arcCanvas.height = 64;
      const arcCtx = arcCanvas.getContext('2d');
      if (arcCtx) {
        arcCtx.fillStyle = '#404040';
        arcCtx.font = '28px sans-serif';
        arcCtx.textBaseline = 'middle';
        arcCtx.fillText(`arc ${arcLenMm.toFixed(0)}`, 4, 32);
      }
      const arcTex = new THREE.CanvasTexture(arcCanvas);
      arcTex.minFilter = THREE.LinearFilter;
      const arcMat = new THREE.SpriteMaterial({ map: arcTex, transparent: true });
      const arcSprite = new THREE.Sprite(arcMat);
      const arcH = 0.25;
      arcSprite.scale.set(arcH * (arcCanvas.width / arcCanvas.height), arcH, 1);
      arcSprite.position.set(arcMidX / 1000, SLICE_Y + 0.01, arcMidY / 1000);
      arcSprite.userData.detailComponent = true;
      arcSprite.userData.bimPickId = p.id;
      grp.add(arcSprite);
    } else if (p.kind === 'angular_dimension') {
      // Render two radial lines and an arc label.
      const angLineMat = new THREE.LineBasicMaterial({ color: p.colour });
      const angPts = [
        new THREE.Vector3(p.vertexMm.xMm / 1000, SLICE_Y + 0.01, p.vertexMm.yMm / 1000),
        new THREE.Vector3(p.rayAMm.xMm / 1000, SLICE_Y + 0.01, p.rayAMm.yMm / 1000),
      ];
      const angPts2 = [
        new THREE.Vector3(p.vertexMm.xMm / 1000, SLICE_Y + 0.01, p.vertexMm.yMm / 1000),
        new THREE.Vector3(p.rayBMm.xMm / 1000, SLICE_Y + 0.01, p.rayBMm.yMm / 1000),
      ];
      const angGeo1 = new THREE.BufferGeometry().setFromPoints(angPts);
      const angGeo2 = new THREE.BufferGeometry().setFromPoints(angPts2);
      const angLine1 = new THREE.Line(angGeo1, angLineMat);
      const angLine2 = new THREE.Line(angGeo2, angLineMat);
      angLine1.userData.detailComponent = true;
      angLine1.userData.bimPickId = p.id;
      angLine2.userData.detailComponent = true;
      angLine2.userData.bimPickId = p.id;
      grp.add(angLine1);
      grp.add(angLine2);
      const daxA = p.rayAMm.xMm - p.vertexMm.xMm;
      const dayA = p.rayAMm.yMm - p.vertexMm.yMm;
      const daxB = p.rayBMm.xMm - p.vertexMm.xMm;
      const dayB = p.rayBMm.yMm - p.vertexMm.yMm;
      const angleA = Math.atan2(dayA, daxA);
      const angleB = Math.atan2(dayB, daxB);
      const angleDeg = Math.abs(((angleB - angleA) * 180) / Math.PI);
      const midAngle = (angleA + angleB) / 2;
      const angR = p.arcRadiusMm / 1000;
      const angLabelX = p.vertexMm.xMm / 1000 + angR * Math.cos(midAngle);
      const angLabelZ = p.vertexMm.yMm / 1000 + angR * Math.sin(midAngle);
      const angCanvas = document.createElement('canvas');
      angCanvas.width = 192;
      angCanvas.height = 64;
      const angCtx = angCanvas.getContext('2d');
      if (angCtx) {
        angCtx.fillStyle = p.colour;
        angCtx.font = '28px sans-serif';
        angCtx.textBaseline = 'middle';
        angCtx.fillText(`${angleDeg.toFixed(1)}°`, 4, 32);
      }
      const angTex = new THREE.CanvasTexture(angCanvas);
      angTex.minFilter = THREE.LinearFilter;
      const angSpriteMat = new THREE.SpriteMaterial({ map: angTex, transparent: true });
      const angSprite = new THREE.Sprite(angSpriteMat);
      const angH = 0.25;
      angSprite.scale.set(angH * (angCanvas.width / angCanvas.height), angH, 1);
      angSprite.position.set(angLabelX, SLICE_Y + 0.01, angLabelZ);
      angSprite.userData.detailComponent = true;
      angSprite.userData.bimPickId = p.id;
      grp.add(angSprite);
    } else if (p.kind === 'revision_cloud') {
      const rcMat = new THREE.LineBasicMaterial({ color: p.colour });
      if (p.boundaryMm.length >= 2) {
        const rcPts = [...p.boundaryMm, p.boundaryMm[0]!].map(
          (v) => new THREE.Vector3(v.xMm / 1000, SLICE_Y + 0.01, v.yMm / 1000),
        );
        const rcGeo = new THREE.BufferGeometry().setFromPoints(rcPts);
        const rcLine = new THREE.Line(rcGeo, rcMat);
        rcLine.userData.detailComponent = true;
        rcLine.userData.bimPickId = p.id;
        grp.add(rcLine);
      }
    } else if (p.kind === 'insulation_annotation') {
      const insMat = new THREE.LineBasicMaterial({ color: p.colour });
      const insPts = [
        new THREE.Vector3(p.startMm.xMm / 1000, SLICE_Y + 0.01, p.startMm.yMm / 1000),
        new THREE.Vector3(p.endMm.xMm / 1000, SLICE_Y + 0.01, p.endMm.yMm / 1000),
      ];
      const insGeo = new THREE.BufferGeometry().setFromPoints(insPts);
      const insLine = new THREE.Line(insGeo, insMat);
      insLine.userData.detailComponent = true;
      insLine.userData.bimPickId = p.id;
      grp.add(insLine);
    }
  }
}

