    const verts = state.phase === 'sketch' ? state.verticesMm : [];
    if (verts.length >= 3) {
      return {
        state: { phase: 'idle' },
        effect: { commitCeiling: { verticesMm: verts }, stillActive: true },
      };
    }
  }
  return { state, effect: { stillActive: true } };
}
