/* ─────────────────────────────────────────────────────────────────────── */

export type TextAnnotationState =
  | { phase: 'idle' }
  | { phase: 'typing'; xMm: number; yMm: number; content: string };

export type TextAnnotationEvent =
  | { kind: 'activate' }
