          rS.userData.detailComponent = true; rS.userData.bimPickId = p.id; grp.add(rS);
        } else if (p.kind === 'arc_length_dimension') {
          const midRad = ((p.startAngleDeg+p.endAngleDeg)/2*Math.PI)/180;
          const arcLen = (Math.abs(p.endAngleDeg-p.startAngleDeg)*Math.PI/180)*p.radiusMm;
          const aLC = document.createElement('canvas'); aLC.width=192; aLC.height=64;
          const aLCtx = aLC.getContext('2d');
          if (aLCtx) { aLCtx.fillStyle='#404040'; aLCtx.font='28px sans-serif'; aLCtx.textBaseline='middle'; aLCtx.fillText(`arc ${arcLen.toFixed(0)}`,4,32); }
          const aLTex = new THREE.CanvasTexture(aLC); aLTex.minFilter = THREE.LinearFilter;
          const aLS = new THREE.Sprite(new THREE.SpriteMaterial({ map: aLTex, transparent: true }));
          aLS.scale.set(0.25*(192/64), 0.25, 1);
          aLS.position.set(p.centerMm.xMm/1000+(p.radiusMm/1000)*Math.cos(midRad), SLICE_Y+0.01, p.centerMm.yMm/1000+(p.radiusMm/1000)*Math.sin(midRad));
          aLS.userData.detailComponent = true; aLS.userData.bimPickId = p.id; grp.add(aLS);
        } else if (p.kind === 'angular_dimension') {
          const angM = new THREE.LineBasicMaterial({ color: p.colour });
          [[[p.vertexMm,p.rayAMm],[p.vertexMm,p.rayBMm]]].flat().forEach(([a,b], i) => {
            const l = new THREE.Line(new THREE.BufferGeometry().setFromPoints([
              new THREE.Vector3(a.xMm/1000, SLICE_Y+0.01, a.yMm/1000),
              new THREE.Vector3(b.xMm/1000, SLICE_Y+0.01, b.yMm/1000),
            ]), angM);
            l.userData.detailComponent = true; l.userData.bimPickId = p.id; grp.add(l);
          });
          const aA = Math.atan2(p.rayAMm.yMm-p.vertexMm.yMm, p.rayAMm.xMm-p.vertexMm.xMm);
          const aB = Math.atan2(p.rayBMm.yMm-p.vertexMm.yMm, p.rayBMm.xMm-p.vertexMm.xMm);
          const angDeg = Math.abs((aB-aA)*180/Math.PI);
          const angC = document.createElement('canvas'); angC.width=192; angC.height=64;
          const angCtx = angC.getContext('2d');
          if (angCtx) { angCtx.fillStyle=p.colour; angCtx.font='28px sans-serif'; angCtx.textBaseline='middle'; angCtx.fillText(`${angDeg.toFixed(1)}°`,4,32); }
          const angTex = new THREE.CanvasTexture(angC); angTex.minFilter = THREE.LinearFilter;
          const angS = new THREE.Sprite(new THREE.SpriteMaterial({ map: angTex, transparent: true }));
          const mA = (aA+aB)/2, aR = p.arcRadiusMm/1000;
          angS.scale.set(0.25*(192/64), 0.25, 1);
          angS.position.set(p.vertexMm.xMm/1000+aR*Math.cos(mA), SLICE_Y+0.01, p.vertexMm.yMm/1000+aR*Math.sin(mA));
          angS.userData.detailComponent = true; angS.userData.bimPickId = p.id; grp.add(angS);
        } else if (p.kind === 'revision_cloud' && p.boundaryMm.length >= 2) {
          const rcL = new THREE.Line(new THREE.BufferGeometry().setFromPoints(
            [...p.boundaryMm, p.boundaryMm[0]!].map(v => new THREE.Vector3(v.xMm/1000, SLICE_Y+0.01, v.yMm/1000))
          ), new THREE.LineBasicMaterial({ color: p.colour }));
          rcL.userData.detailComponent = true; rcL.userData.bimPickId = p.id; grp.add(rcL);
        } else if (p.kind === 'insulation_annotation') {
          const insL = new THREE.Line(new THREE.BufferGeometry().setFromPoints([
            new THREE.Vector3(p.startMm.xMm/1000, SLICE_Y+0.01, p.startMm.yMm/1000),
            new THREE.Vector3(p.endMm.xMm/1000, SLICE_Y+0.01, p.endMm.yMm/1000),
          ]), new THREE.LineBasicMaterial({ color: p.colour }));
          insL.userData.detailComponent = true; insL.userData.bimPickId = p.id; grp.add(insL);
        }
      }
    }

    // ANN-01/'''
        pc = pc.replace(old_pc, new_pc, 1)
        print('PlanCanvas: replaced OK')

with open(path_pc, 'w') as f:
    f.write(pc)
print(f'PlanCanvas written: {pc.count(chr(10))} lines, spot_elevation: {"spot_elevation" in pc}')

